import "./SocialButtons.scss";

import React, { Component } from "react";
import {
  faBehance,
  faDiscord,
  faGithub,
  faInstagram,
  faItchIo,
  faLinkedinIn,
  faSteam,
  faTwitter,
} from "@fortawesome/free-brands-svg-icons";

import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import Popper from "../Popper/Popper";
import { faEnvelope } from "@fortawesome/free-regular-svg-icons";
import { pageview } from "react-ga";

interface Props {
  className?: string;
}

export default class SocialButtons extends Component<Props> {
  GAPageView(page: string): void {
    pageview(`${window.location.hash}/${page}`);
  }

  render(): JSX.Element {
    const { GAPageView } = this,
      { className } = this.props;
    return (
      <div className='d-flex overflow-auto w-100 py-2'>
        <Popper text='Github' trigger='hover focus' placement='bottom'>
          <a
            href='https://github.com/ahmet-cetinkaya'
            target='_blank'
            rel='noreferrer'
            className={`rounded-circle hoverCircleBackground equal mx-1 ${className}`}
            onClick={() => GAPageView("github")}
          >
            <FontAwesomeIcon icon={faGithub} color='white' />
          </a>
        </Popper>
        <Popper text='LinkedIn' trigger='hover focus' placement='bottom'>
          <a
            href='https://www.linkedin.com/in/ahmet-cetinkaya'
            target='_blank'
            rel='noreferrer'
            className={`rounded-circle hoverCircleBackground equal mx-1 ${className}`}
            onClick={() => GAPageView("linkedin")}
          >
            <FontAwesomeIcon icon={faLinkedinIn} color='white' />
          </a>
        </Popper>
        <Popper text='mail@ahmetcetinkaya.info' trigger='hover focus' placement='bottom'>
          <a
            href='mailto:mail@ahmetcetinkaya.info'
            target='_blank'
            rel='noreferrer'
            className={`rounded-circle hoverCircleBackground equal mx-1 ${className}`}
            onClick={() => GAPageView("mail")}
          >
            <FontAwesomeIcon icon={faEnvelope} color='white' />
          </a>
        </Popper>
        <Popper text='Behance' trigger='hover focus' placement='bottom'>
          <a
            href='https://www.behance.net/ahmetcetinkaya'
            target='_blank'
            rel='noreferrer'
            className={`rounded-circle hoverCircleBackground equal mx-1 ${className}`}
            onClick={() => GAPageView("behance")}
          >
            <FontAwesomeIcon icon={faBehance} color='white' />
          </a>
        </Popper>
        <Popper text='itch.io' trigger='hover focus' placement='bottom'>
          <a
            href='https://ahmetcetinkaya.itch.io/'
            target='_blank'
            rel='noreferrer'
            className={`rounded-circle hoverCircleBackground equal mx-1 ${className}`}
            onClick={() => GAPageView("itch.io")}
          >
            <FontAwesomeIcon icon={faItchIo} color='white' />
          </a>
        </Popper>
        <Popper text='Twitter' trigger='hover focus' placement='bottom'>
          <a
            href='https://twitter.com/ahmet4cetinkaya'
            target='_blank'
            rel='noreferrer'
            className={`rounded-circle hoverCircleBackground equal mx-1 ${className}`}
            onClick={() => GAPageView("twitter")}
          >
            <FontAwesomeIcon icon={faTwitter} color='white' />
          </a>
        </Popper>
        <Popper text='Instagram' trigger='hover focus' placement='bottom'>
          <a
            href='https://www.instagram.com/ahmet4cetinkaya'
            target='_blank'
            rel='noreferrer'
            className={`rounded-circle hoverCircleBackground equal mx-1 ${className}`}
            onClick={() => GAPageView("instagram")}
          >
            <FontAwesomeIcon icon={faInstagram} color='white' />
          </a>
        </Popper>
        <Popper text='Discord' trigger='hover focus' placement='bottom'>
          <a
            href='https://discordapp.com/users/248840559039348736'
            target='_blank'
            rel='noreferrer'
            className={`rounded-circle hoverCircleBackground equal mx-1 ${className}`}
            onClick={() => GAPageView("discord")}
          >
            <FontAwesomeIcon icon={faDiscord} color='white' />
          </a>
        </Popper>
        <Popper text='Steam' trigger='hover focus' placement='bottom'>
          <a
            href='https://steamcommunity.com/id/J4UNE'
            target='_blank'
            rel='noreferrer'
            className={`rounded-circle hoverCircleBackground equal mx-1 ${className}`}
            onClick={() => GAPageView("steam")}
          >
            <FontAwesomeIcon icon={faSteam} color='white' />
          </a>
        </Popper>
      </div>
    );
  }
}
